#pragma mark - action event handler

- (void)onPressVApp:(WBVAppModel *)vapp isFromVappNotification:(BOOL)isFromVappNotification {
    [WBEventManager logVappTryLaunchEvent:vapp];
    NSString *oaaVersion = [[NSString alloc] initWithFormat:@"%s", oaa_version()];
    [[WBNetworkManager defaultManager] getLatestVappInfoWithVappId:vapp.vid oaaVersion:oaaVersion callback:^(WBVAppDetailHttpModel * _Nullable requestedVapp, NSError * _Nullable error) {
        if (error) {
            [SVProgressHUD showErrorWithStatus:error.localizedDescription];
            self.vappLaunching = false;
            return;
        }
        if (vapp.versionInfo.ef != requestedVapp.ef) {
            vapp.versionInfo.ef = requestedVapp.ef;
        }
        if (vapp.versionInfo.restrictionWords.hash != requestedVapp.restrictionWords.hash) {
            vapp.versionInfo.restrictionWords = requestedVapp.restrictionWords;
        }
        if (self.isVappLaunching) return;
        self.vappLaunching = true;
        if (isFromVappNotification && vapp.status == WBVappStatusInited) {
            [self launchVappWithVappStatusCheck:vapp];
        } else {
            [self vipAndPasswordCheckedLaunchForVApp:vapp];
        }
    }];
}

