- (void)onRemoveMenuSelectedForVApp:(WBVAppModel *)vapp {
    UIAlertController *alertVc = [UIAlertController alertControllerWithTitle:@"删除应用" message:@"该应用所有数据都会被删除" preferredStyle:UIAlertControllerStyleAlert];
    [alertVc addAction:[UIAlertAction actionWithTitle:@"取消" style:UIAlertActionStyleDefault handler:nil]];
    [alertVc addAction:[UIAlertAction actionWithTitle:@"删除" style:UIAlertActionStyleDestructive handler:^(UIAlertAction * _Nonnull action) {
        if (vapp.status == WBVappStatusResourceWaitingDownload
            || vapp.status == WBVappStatusResourceDownloading
            || vapp.status == WBVappStatusResourceInstalling) {
            [SVProgressHUD showErrorWithStatus:@"有资源正在下载或安装，请稍后再试。"];
            return;
        }
        [[NSNotificationCenter defaultCenter] postNotificationName:WBDeleteDownloadResCancelNotification object:nil userInfo:nil];
        [self removeVApp:vapp];
    }]];
    [[WBAppManager getUIApplicationRootViewController] presentViewController:alertVc animated:YES completion:nil];
}

- (void)onUpdateMenuSelectedForVApp:(WBVAppModel *)vapp {
    NSString *oaaVersion = [[NSString alloc] initWithFormat:@"%s", oaa_version()];
    [[WBNetworkManager defaultManager] getLatestVappInfoWithVappId:vapp.vid oaaVersion:oaaVersion callback:^(WBVAppDetailHttpModel * _Nullable requestedVapp, NSError * _Nullable error) {
        if (error) {
            [SVProgressHUD showErrorWithStatus:error.localizedDescription];
            return;
        }
        if (![vapp.versionInfo.ipaHash isEqualToString:requestedVapp.ipa_hash]) {
            [vapp updateWithVAppDetailModel:requestedVapp];
            [self downloadVApp:vapp];
        } else if (![vapp.versionInfo.resHash isEqualToString:requestedVapp.res_hash]) {
            [vapp updateWithVAppDetailModel:requestedVapp];
            [self downloadVAppRes:vapp];
        } else {
            [SVProgressHUD showSuccessWithStatus:@"已是最新版本"];
        }
    }];
}

