- (BOOL)gestureRecognizer:(UIGestureRecognizer *)gestureRecognizer shouldRecognizeSimultaneouslyWithGestureRecognizer:(UIGestureRecognizer *)otherGestureRecognizer {
    UIView *gestureView = gestureRecognizer.view;
    UIView *otherGestureView = otherGestureRecognizer.view;

    BOOL isGestureViewInFeature = NO;
    BOOL isOtherGestureViewInFeature = NO;

    // 检查第一个手势视图是否在 Feature 视图中
    UIView *superviewIterator = gestureView;
    while (superviewIterator) {
        if ([superviewIterator isKindOfClass:[WBHomeVappFeatureView class]]) {
            isGestureViewInFeature = YES;
            break;
        }
        superviewIterator = superviewIterator.superview;
    }

    // 检查第二个手势视图是否在 Feature 视图中
    superviewIterator = otherGestureView;
    while (superviewIterator) {
        if ([superviewIterator isKindOfClass:[WBHomeVappFeatureView class]]) {
            isOtherGestureViewInFeature = YES;
            break;
        }
        superviewIterator = superviewIterator.superview;
    }

    if (isGestureViewInFeature || isOtherGestureViewInFeature) {
        return YES;
    }
    return NO;
}


