- (__kindof UICollectionViewCell *)collectionView:(UICollectionView *)collectionView cellForItemAtIndexPath:(NSIndexPath *)indexPath {
    if (indexPath.row == self.dualvapps.count) { //加号
        UICollectionViewCell *cell = [collectionView dequeueReusableCellWithReuseIdentifier:reuseIdentifier_add forIndexPath:indexPath];

        UIImageView *customImageView = [[UIImageView alloc] initWithImage:[UIImage imageNamed:@"Home_addVapp_button"]];
        customImageView.frame = CGRectMake(20, 15, ZOOM(24), ZOOM(24));
        customImageView.center = CGPointMake(cell.contentView.bounds.size.width/2, ZOOM(18));
        [cell.contentView addSubview:customImageView];
        cell.backgroundColor = RGB(246, 246, 246);
        cell.layer.cornerRadius = ZOOM(12);

        return cell;
    } else {//vapp
        WBVAppModel *vapp = self.dualvapps[indexPath.row];
        WBVappCollectionViewCell *cell = [collectionView dequeueReusableCellWithReuseIdentifier:reuseIdentifier forIndexPath:indexPath];
        cell.vapp = vapp;
        cell.delegate = self;
        cell.parentVC = self;
        if (!cell.vapp.isDownload || WBSettingManager.sharedManager.HideVIPPrivilege) {
            for (WBHomeVappFeatureView *view in cell.selectedFeatureViews) {
                view.hidden = YES;
            }
            cell.hideFeaturesButton.hidden = YES;
            cell.editFeaturesButton.hidden = YES;
            cell.vappBackView.backgroundColor = [UIColor clearColor];
            cell.backgroundColor = [UIColor clearColor];
        } else {
            for (WBHomeVappFeatureView *view in cell.selectedFeatureViews) {
                view.hidden = NO;
            }
            cell.hideFeaturesButton.hidden = NO;
            cell.editFeaturesButton.hidden = NO;
            cell.vappBackView.backgroundColor = [UIColor whiteColor];
            cell.backgroundColor = RGB(246, 246, 246);
        }
        cell.moreButton.hidden = !cell.vapp.isDownload;
        return cell;
    }
}

