- (void)authorize:(WBVAppModel *)vapp successBlock:(WBActionBlock)block {
    void (^passwordCheckedLaunchBlock)(void) = ^{
        if ((WBSettingManager.sharedManager.IsVIP || WBSettingManager.sharedManager.IsSVIP) && vapp.featureStatusInfo.isLockSwitchOn) {
            [self showPasswordView:vapp successBlock:^{
                vapp.authorized = TRUE;
                block();
            } failBlock:nil];
        } else {
            vapp.authorized = TRUE;
            block();
        }
    };

    if (WBSettingManager.sharedManager.IsVIP || WBSettingManager.sharedManager.IsSVIP || self.isSkipVIPCheckWhenLaunch || vapp.isAuthorized) {
        passwordCheckedLaunchBlock();
    } else if (WBSettingManager.sharedManager.IsTrial) {
        [self showNotVIPBottomPopup:vapp launchBlock:passwordCheckedLaunchBlock];
    } else {
        [self showRunOutOfFreeTimeBottomPopup];
    }
}


