- (void)removeVApp:(WBVAppModel *)vapp {
    [SVProgressHUD showWithStatus:@"正在删除"];
    dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.1 * NSEC_PER_SEC)),dispatch_get_main_queue(), ^{
        [WBVAppManager.sharedManager removeVApp:vapp callback:^(WBVAppModel * _Nonnull vapp, VAppActionErrorCode errorCode) {
            if (errorCode == actionErrorSuccess) {
                [self.collectionView reloadData];
                dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.1 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
                    [SVProgressHUD showSuccessWithStatus:@"已删除"];
                    vapp.isDownload = NO;
                    [self.collectionView reloadData];
                });
            }
        }];
    });
}

