        [self handleGetVappCallbackWithVApp:vapp andErrorCode:errorCode];
    }];
}

- (void)handleGetVappCallbackWithVApp:(WBVAppModel *)vapp andErrorCode:(VAppActionErrorCode)errorCode {
    if (errorCode == actionErrorSuccess) {
        vapp.isDownload = YES;
        [self.collectionView reloadData];
        UITabBarController *mainVc = (UITabBarController *)[WBAppManager getUIApplicationRootViewController];
        if (![mainVc isKindOfClass:[WBMainViewController class]]) return;
        [mainVc setSelectedViewController:mainVc.childViewControllers.firstObject];
    } else {
        [self wb_showAlertWithTitle:@"获取失败" message:@"请检查网络后重试"];
    }
}

