- (BOOL)wb_shouldIgnoreCollectionGestureForTouch:(UITouch *)touch {
    UIView *touchView = touch.view;
    while (touchView) {
        if ([touchView isKindOfClass:[WBHomeVappFeatureView class]] || [touchView isKindOfClass:[UIControl class]]) {
            return YES;
        }
        touchView = touchView.superview;
    }

    CGPoint point = [touch locationInView:self.collectionView];
    for (UICollectionViewCell *cell in self.collectionView.visibleCells) {
        if (![cell isKindOfClass:[WBVappCollectionViewCell class]]) {
            continue;
        }

        WBVappCollectionViewCell *vappCell = (WBVappCollectionViewCell *)cell;
        if ([self wb_interactiveView:vappCell.startButton containsTouchPoint:point] ||
            [self wb_interactiveView:vappCell.moreButton containsTouchPoint:point] ||
            [self wb_interactiveView:vappCell.hideFeaturesButton containsTouchPoint:point] ||
            [self wb_interactiveView:vappCell.editFeaturesButton containsTouchPoint:point]) {
            return YES;
        }

        for (WBHomeVappFeatureView *featureView in vappCell.selectedFeatureViews) {
            if ([self wb_interactiveView:featureView containsTouchPoint:point]) {
                return YES;
            }
        }
    }
    return NO;
}仔细给我讲讲这个方法

