- (BOOL)hasIPA:(NSString*)bundleId ofSha1Hash:(NSString*)hash {
    NSString *path = [_cacheRoot stringByAppendingPathComponent:[WBUtility getCodeNameSaltedSha1Hash:bundleId]];
    if ([NSFileManager.defaultManager fileExistsAtPath:path] == TRUE) {
